#### MTTH（Mean Time To Happen）
public class EventTrigger
    // MTTH基础值（天数）
    public float BaseMTTH { get; set; }
    // 触发条件
    public List<TriggerCondition> Conditions { get; set; }
    // 修正因子
    public List<MTTHModifier> Modifiers { get; set; }
    public float CalculateMTTH(Country country)
        float mtth = BaseMTTH;
        // 应用所有修正
        foreach (var modifier in Modifiers)
            if (modifier.CheckCondition(country))
                mtth *= modifier.Factor;
        return mtth;
    public bool CheckTrigger(Country country)
        // 1. 检查所有条件
        foreach (var condition in Conditions)
            if (!condition.Check(country))
                return false;
        // 2. 计算触发几率
        float mtth = CalculateMTTH(country);
        float dailyChance = 1.0f / mtth;
        // 3. 随机判定
        return Random.value < dailyChance;

